import{_ as a,o as i,c as n,a2 as t}from"./chunks/framework.4hJCcvDE.js";const c=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"blog/设计模式_001-浅析Unity的ECS模式.md","filePath":"blog/设计模式_001-浅析Unity的ECS模式.md","lastUpdated":1784835052000}'),e={name:"blog/设计模式_001-浅析Unity的ECS模式.md"};function l(p,s,r,h,d,o){return i(),n("div",null,[...s[0]||(s[0]=[t(`<p>最近发现unity的entity package里面有unity ecs模块的所有代码，所以现在主要在看这个东西学习。 看了发现要自己实现一个可以脱离unity运行的简易版本也是有一定难度的</p><h2 id="一、unity-ecs-vs-自研-soa-ecs" tabindex="-1">一、Unity ECS vs 自研 SOA-ECS <a class="header-anchor" href="#一、unity-ecs-vs-自研-soa-ecs" aria-label="Permalink to &quot;一、Unity ECS vs 自研 SOA-ECS&quot;">​</a></h2><p>在研究 Unity ECS 源码的过程中，发现它的核心设计思路可以拆为三层：</p><ol><li><strong>Archetype/Chunk 内存布局</strong> — Unity 的做法是把相同组件组合的实体放在同一块连续内存（Chunk）里，16KB 一块，遍历时走 Chunk 而不是走 Entity</li><li><strong>System 调度</strong> — 按依赖关系排序 System，Job System 并行执行</li><li><strong>Burst Compiler</strong> — 把 C# 编译为本机代码，在 Chunk 遍历中获得接近 C++ 的性能</li></ol><p>Unity 这套设计是针对通用 ECS 场景的——场景里可能有几百种不同的组件组合，每个系统的访问模式可能完全不同。但对于塔防这种特定项目，组件种类是固定的（敌人、塔、玩家、世界），Archetype 的灵活性反而带来了额外的复杂度和内存碎片。</p><p>于是我基于 Unity ECS 的思想，做了一个精简版的 SOA（Struct of Arrays）架构，专门服务于塔防性能基准测试项目 <strong>BattleSystem-ECS</strong>。</p><p>核心区别：</p><table tabindex="0"><thead><tr><th></th><th>Unity ECS</th><th>自研 SOA-ECS</th></tr></thead><tbody><tr><td>内存布局</td><td>Archetype/Chunk 动态分配</td><td>5 个固定 ComponentStore（Enemy/Tower/Player/World + 核心）</td></tr><tr><td>组件访问</td><td>Chunk 遍历 + 迭代器</td><td>直接索引 parallel float[]/int[]/bool[] 数组</td></tr><tr><td>并行</td><td>Job System（Burst 编译）</td><td>Parallel.For + 手动两阶段安全</td></tr><tr><td>性能上限</td><td>依赖 Burst，接近 C++</td><td>依赖内存布局，C# GC 边界内优化</td></tr><tr><td>复杂度</td><td>高（需要理解 Chunk/Archetype/EntityQuery）</td><td>中（直接操作数组，无语法糖）</td></tr></tbody></table><h2 id="二、5-个-componentstore-的设计" tabindex="-1">二、5 个 ComponentStore 的设计 <a class="header-anchor" href="#二、5-个-componentstore-的设计" aria-label="Permalink to &quot;二、5 个 ComponentStore 的设计&quot;">​</a></h2><p>把组件按领域拆为 5 个 partial class，每个自包含其字段和访问方法：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Core/ComponentStore.cs          # 核心：常量 MAX_ENTITIES=100K、位置、实体 CRUD、活跃 ID、死亡队列</span></span>
<span class="line"><span>Core/ComponentStore_Enemy.cs    # 敌人：Health/Armor/CC/Bleed/BT/ActionEnum...（约 40+ 字段）</span></span>
<span class="line"><span>Core/ComponentStore_Tower.cs    # 塔：Damage/Range/Targeting/Projectile/Ammo/Overcharge...</span></span>
<span class="line"><span>Core/ComponentStore_Player.cs   # 玩家：Attack/Health/Shield/Mana/Gold/Buff/TechTree...</span></span>
<span class="line"><span>Core/ComponentStore_World.cs    # 世界：Weather/DayNight/Adaptive/Resource/Fog...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>每个文件里的数据都是平行数组，比如敌人组件：</p><div class="language-csharp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">float</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[]  </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">EnemyHealth</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 100K 个 float 连续存储</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">float</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[]  </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">EnemyMaxHealth</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">float</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[]  </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">EnemyMoveSpeed</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">bool</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[]   </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">EnemyActive</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[]    </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">EnemyGoldReward</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">EnemyActionType</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[] </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">EnemyActionEnum</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 预计算 enum，热路径无字符串比较</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">BTCachedTree</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[] </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">EnemyBehaviorTree</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 预缓存行为树，O(1) 访问</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>为什么要拆 partial class？因为 5 个文件加起来上千行，不拆的话单文件内 IDE 的 intellisense 会非常慢。而且从领域角度看，敌人系统和玩家系统的字段几乎不会交叉引用，分开维护更清晰。</p><h2 id="三、从-遍历所有实体-到-活跃-id-列表" tabindex="-1">三、从&quot;遍历所有实体&quot;到&quot;活跃 ID 列表&quot; <a class="header-anchor" href="#三、从-遍历所有实体-到-活跃-id-列表" aria-label="Permalink to &quot;三、从&quot;遍历所有实体&quot;到&quot;活跃 ID 列表&quot;&quot;">​</a></h2><p>一个看了 Unity ECS 源码才深刻体会到的优化：不要遍历全量数组，只遍历活跃的。</p><p>最开始的设计是所有系统这样写的：</p><div class="language-csharp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> i</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; i </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> store.NextEntityId; i</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">++</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 遍历到最大创建数</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (store.EnemyActive[i])  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 跳过不活跃的</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>当 MAX_ENTITIES 是 100K 但实际只有 2000 活跃敌人时，98% 的遍历是在检查 <code>bool[]</code> 后跳过。改为维护 <code>ActiveEnemyIds</code>（<code>List&lt;int&gt;</code>），系统只遍历活跃 ID：</p><div class="language-csharp vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 返回副本，防止外部篡改</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">public</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> IReadOnlyList</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">GetAllActiveEnemyIds</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    =&gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> new</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> List</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;(ActiveEnemyIds);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>注意返回的是<strong>副本</strong>，不是内部引用。早期版本直接返回 <code>ActiveEnemyIds</code>，导致一个 P0 bug：某系统迭代列表时另一个系统修改了列表长度，触发 <code>InvalidOperationException</code>。虽然我们这个项目是单线程串行执行系统，但列表的生命周期跨越多个系统调用，副本是必要的防御。</p><h2 id="四、行为树预缓存" tabindex="-1">四、行为树预缓存 <a class="header-anchor" href="#四、行为树预缓存" aria-label="Permalink to &quot;四、行为树预缓存&quot;">​</a></h2><p>Unity ECS 的一个痛点是在运行时动态查找组件——<code>EntityManager.GetComponentData&lt;T&gt;(entity)</code> 本质上是 Dictionary 查找，热路径上开销不小。</p><p>BattleSystem-ECS 的做法是：波次生成时直接把行为树 JSON 解析并缓存到 SOA 数组中：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WaveSpawning</span></span>
<span class="line"><span>  → BTCachedTreeEvaluator.Build(json)   // 构建扁平化树结构</span></span>
<span class="line"><span>  → store.EnemyBehaviorTree[entityId] = tree  // 存到 SOA 数组</span></span>
<span class="line"><span>EnemyAISystem.Update</span></span>
<span class="line"><span>  → tree = store.EnemyBehaviorTree[entityId]  // O(1) 数组索引，无 Dictionary 查找</span></span>
<span class="line"><span>  → tree.EvaluateWithEnum() → EnemyActionEnum  // 结果直接写 enum</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>整个 EnemyAISystem 的热路径上没有一次 Dictionary 查找、没有一次字符串比较，全部是数组索引和枚举判断。</p><h2 id="五、和-unity-ecs-路线的一个分歧" tabindex="-1">五、和 Unity ECS 路线的一个分歧 <a class="header-anchor" href="#五、和-unity-ecs-路线的一个分歧" aria-label="Permalink to &quot;五、和 Unity ECS 路线的一个分歧&quot;">​</a></h2><p>Unity ECS 强调&quot;无继承、纯数据&quot;，所有逻辑在 System 里做。我们游戏里则是按领域分组保留了部分行为：比如 <code>BTCachedTreeEvaluator</code> 本身有复杂的状态机逻辑，放在 System 里会让代码变成面条。最后的做法是——数据用 SOA 存储（纯数组），但允许行为对象存在（如 Evaluator、各种 Group），只要这些对象<strong>本身不持有可变共享状态</strong>即可。</p><p>这种折中在实际工程中是合理的：纯数据 ECS 在理论上是完美的，但在复杂业务逻辑（比如行为树评估、技能效果链）面前，强行把几百行逻辑塞进 System 的 Update 里，可维护性反而变差。</p><h2 id="六、性能" tabindex="-1">六、性能 <a class="header-anchor" href="#六、性能" aria-label="Permalink to &quot;六、性能&quot;">​</a></h2><p>项目目前跑出的基准（2026-06）：</p><table tabindex="0"><thead><tr><th>模式</th><th>FPS</th><th>说明</th></tr></thead><tbody><tr><td>mode2（合并热路径，10K 敌 ×500 帧）</td><td>7385</td><td>绕过真实系统调用链路</td></tr><tr><td>mode4（真实系统链路，10K 敌 ×500 帧）</td><td>3125</td><td>每个系统独立执行，更接近实际游戏</td></tr><tr><td>mode5（完整一局，400 帧）</td><td>2848</td><td>真实波次生成、5 关全通</td></tr></tbody></table><p>mode2 和 mode4 的差距（7385 vs 3125）是一个很关键的教训：优化工具很容易制造&quot;看起来很快&quot;的假象。mode2 把几个系统的 Update 合并到一个循环里，绕过了 20+ 个 SystemGroup 的调度开销、接口分发和组件查找，FPS 翻倍——但这个路径在实际游戏里根本不存在。实际游戏一定是走 mode4 的真实链路。如果你用 mode2 的数据去说服自己做性能优化，很容易去优化一些根本不存在的&quot;热点&quot;。</p><p>目前 C# 单线程（未开 Burst、未用 IL2CPP），纯靠 SOA 内存布局和 <code>Parallel.For</code> 做到了 3000+ FPS。如果用 Burst 把 <code>Parallel.For</code> 里的循环编译为本机代码，预计还有 2-3x 的空间。</p><h2 id="参考文献" tabindex="-1">参考文献 <a class="header-anchor" href="#参考文献" aria-label="Permalink to &quot;参考文献&quot;">​</a></h2><ul><li><a href="https://blog.codingnow.com/2017/06/overwatch_ecs.html" target="_blank" rel="noreferrer">浅谈《守望先锋》中的 ECS 构架--云风</a></li><li><a href="https://github.com/Unity-Technologies/EntityComponentSystemSamples" target="_blank" rel="noreferrer">Unity ECS 源码</a></li><li><a href="https://github.com/luoxixuan/battlesystem-ecs" target="_blank" rel="noreferrer">GitHub — BattleSystem-ECS</a>（个人项目，本文相关内容来自此仓库）</li><li>本项目文档 [docs/architecture.md]</li><li>本项目文档 [docs/philosophy.md]</li></ul>`,36)])])}const E=a(e,[["render",l]]);export{c as __pageData,E as default};
